const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  const body = raw.body || raw;
  const event = body.event || '';
  const data = body.data || {};

  const eventosValidos = ['messages.upsert', 'send.message', 'messages.update'];
  if (!eventosValidos.includes(event)) {
    results.push({ json: { skip: true, event: event || 'desconocido' } });
    continue;
  }

  if (event === 'messages.update') {
    const updates = Array.isArray(data) ? data : [data];
    const update = updates[0] || {};
    const key = update.key || {};
    const status = update.update ? update.update.status : null;

    let estadoNuevo = null;
    if (status === 3) estadoNuevo = 'entregado';
    else if (status === 4) estadoNuevo = 'leido';
    else if (status === 5) estadoNuevo = 'leido';

    results.push({
      json: {
        tipo_evento: 'update',
        external_id: key.id || '',
        estado_nuevo: estadoNuevo,
        skip: !estadoNuevo
      }
    });
    continue;
  }

  const key = data.key || {};
  const message = data.message || {};
  const pushName = data.pushName || '';

  let contenido = '';
  let contenido_tipo = 'texto';

  if (message.conversation) {
    contenido = message.conversation;
  } else if (message.extendedTextMessage && message.extendedTextMessage.text) {
    contenido = message.extendedTextMessage.text;
  } else if (message.imageMessage) {
    contenido = message.imageMessage.caption || '[Imagen]';
    contenido_tipo = 'imagen';
  } else if (message.audioMessage) {
    contenido = '[Audio]';
    contenido_tipo = 'audio';
  } else if (message.videoMessage) {
    contenido = message.videoMessage.caption || '[Video]';
    contenido_tipo = 'video';
  } else if (message.documentMessage) {
    contenido = message.documentMessage.fileName || '[Documento]';
    contenido_tipo = 'documento';
  } else if (message.locationMessage) {
    contenido = '[Ubicacion: ' + message.locationMessage.degreesLatitude + ', ' + message.locationMessage.degreesLongitude + ']';
    contenido_tipo = 'ubicacion';
  } else {
    contenido = '[Mensaje no soportado]';
  }

  const fromMe = key.fromMe === true;
  const direccion = fromMe ? 'saliente' : 'entrante';

  const remoteJid = key.remoteJid || '';
  const telefono = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '');

  if (remoteJid.indexOf('@g.us') !== -1) {
    results.push({ json: { skip: true, motivo: 'mensaje_grupo' } });
    continue;
  }

  results.push({
    json: {
      tipo_evento: 'mensaje',
      skip: false,
      telefono: telefono,
      contenido: contenido,
      contenido_tipo: contenido_tipo,
      direccion: direccion,
      external_id: key.id || '',
      remitente_nombre: pushName,
      estado: fromMe ? 'enviado' : 'recibido'
    }
  });
}

return results;

