// Buscar conversacion de Chatwoot para enlazar el mensaje con deep link
// Ejecuta 2 llamadas: buscar contacto por telefono → obtener conversacion mas reciente

const CHATWOOT_URL = 'https://crm-chatwoot-a360.vcheqs.easypanel.host';
const CHATWOOT_TOKEN = 'C2D4BxQadaEwN5wAwBaGHC6e';
const ACCOUNT_ID = 1;
const SUPABASE_URL = 'https://rvxmczogxoncdlxpptgb.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InJ2eG1jem9neG9uY2RseHBwdGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTg5OTMwMiwiZXhwIjoyMDgxNDc1MzAyfQ.8RHtJEXpFS5eR5eSEn15iQQ4BJKWGGmFFXYqUQQzB-8';

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Obtener datos del mensaje y del registro insertado
    const telefono = $('Extraer Datos Mensaje').item.json.telefono;
    const insertResp = item.json;
    // Supabase con Prefer:return=representation devuelve array
    const recordId = Array.isArray(insertResp) ? insertResp[0]?.id : insertResp?.id;

    if (!recordId || !telefono) {
      results.push({ json: { skip: true, motivo: 'sin_record_o_telefono' } });
      continue;
    }

    // 1. Buscar contacto en Chatwoot por telefono
    const searchResp = await fetch(
      `${CHATWOOT_URL}/api/v1/accounts/${ACCOUNT_ID}/contacts/search?q=${encodeURIComponent(telefono)}&include_contacts=true`,
      { headers: { 'api_access_token': CHATWOOT_TOKEN, 'Content-Type': 'application/json' } }
    );

    if (!searchResp.ok) {
      results.push({ json: { skip: true, motivo: 'chatwoot_search_error', status: searchResp.status } });
      continue;
    }

    const searchData = await searchResp.json();
    // Chatwoot puede devolver payload.contacts (v2) o payload como array directo
    const contacts = searchData.payload?.contacts
      || (Array.isArray(searchData.payload) ? searchData.payload : [])
      || [];

    if (!contacts.length) {
      results.push({ json: { skip: true, motivo: 'contacto_no_encontrado', telefono, record_id: recordId } });
      continue;
    }

    const contactId = contacts[0].id;

    // 2. Obtener conversaciones del contacto
    const convsResp = await fetch(
      `${CHATWOOT_URL}/api/v1/accounts/${ACCOUNT_ID}/contacts/${contactId}/conversations`,
      { headers: { 'api_access_token': CHATWOOT_TOKEN, 'Content-Type': 'application/json' } }
    );

    if (!convsResp.ok) {
      results.push({ json: { skip: true, motivo: 'chatwoot_convs_error', contactId } });
      continue;
    }

    const convsData = await convsResp.json();
    const conversations = convsData.payload || [];

    if (!conversations.length) {
      results.push({ json: { skip: true, motivo: 'sin_conversaciones', contactId } });
      continue;
    }

    // Tomar la conversacion con ID mas alto (la mas reciente)
    const latestConv = conversations.reduce(
      (max, c) => (c.id > max.id ? c : max),
      conversations[0]
    );

    results.push({
      json: {
        skip: false,
        record_id: recordId,
        chatwoot_conversation_id: String(latestConv.id)
      }
    });

  } catch (e) {
    results.push({ json: { skip: true, motivo: 'exception', error: e.message } });
  }
}

return results;
